#include<bits/stdc++.h>
using namespace std;
long long n,del[100010],son[100010],len[100010];
long long ans;
vector<long long> mp[100010];
deque<long long> f[100010],g[100010];
void dfs1(long long x,long long fa=0)
{
    son[x]=0;
    len[x]=0;
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs1(i,x);
            if(len[i]>=len[son[x]])
            {
                son[x]=i;
                len[x]=len[i]+1;
            }
        }
    }
}
void dfs(long long x,long long fa=0)
{
    if(son[x]==0)
    {
        f[x].push_back(1);
        g[x].push_back(0);
        return;
    }
    dfs(son[x],x);
    swap(f[x],f[son[x]]);
    swap(g[x],g[son[x]]);
    f[x].push_back(1);
    g[x].push_back(0);
    g[x].push_back(0);
    g[x].pop_front();
    ans+=g[x][0];
    for(long long i:mp[x])
    {
        if(i!=fa&&i!=son[x])
        {
            dfs(i,x);
            for(long long j=0;j<len[i];j++)
            {
                ans+=1ll*f[x][len[x]-j]*g[i][j+1];
            }
            for(long long j=0;j<=len[i];j++)
            {
                ans+=1ll*f[i][len[i]-j]*g[x][j+1];
            }
            for(long long j=0;j<=len[i];j++)
            {
                g[x][j+1]+=f[x][len[x]-j-1]*f[i][len[i]-j];
            }
            for(long long j=0;j<len[i];j++)
            {
                g[x][j]+=g[i][j+1];
            }
            for(long long j=0;j<=len[i];j++)
            {
                f[x][len[x]-j-1]+=f[i][len[i]-j];
            }
        }
    }
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs(1);
    printf("%lld",ans);
    return 0;
}
